// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";
import bcrypt from "bcryptjs";
import jwt from "jsonwebtoken";

const app = express();
const PORT = 3000;
const JWT_SECRET = "benchmark-secret";
const db = new Database("data.db");

db.pragma("journal_mode = WAL");
db.pragma("foreign_keys = ON");
db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const bookmarkColumns = db.prepare("PRAGMA table_info(bookmarks)").all() as {
  name: string;
}[];

if (!bookmarkColumns.some((column) => column.name === "folder_id")) {
  db.exec(
    "ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL",
  );
}

if (!bookmarkColumns.some((column) => column.name === "user_id")) {
  db.exec("ALTER TABLE bookmarks ADD COLUMN user_id INTEGER REFERENCES users(id) ON DELETE CASCADE");
}

const folderColumns = db.prepare("PRAGMA table_info(folders)").all() as {
  name: string;
}[];

if (!folderColumns.some((column) => column.name === "user_id")) {
  db.exec("ALTER TABLE folders ADD COLUMN user_id INTEGER REFERENCES users(id) ON DELETE CASCADE");
}

app.use(express.json());

type JwtPayload = {
  userId: number;
};

type AuthenticatedRequest = express.Request & {
  user: {
    id: number;
  };
};

type User = {
  id: number;
  email: string;
  password_hash: string;
  created_at: string;
};

type PublicUser = Omit<User, "password_hash">;

type Bookmark = {
  id: number;
  user_id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  user_id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type FolderWithBookmarks = Folder & {
  bookmarks: Bookmark[];
};

const getUserByEmailStatement = db.prepare("SELECT * FROM users WHERE email = ?");

const getUserByIdStatement = db.prepare("SELECT * FROM users WHERE id = ?");

const createUserStatement = db.prepare(`
  INSERT INTO users (email, password_hash, created_at)
  VALUES (@email, @password_hash, @created_at)
`);

const listBookmarksStatement = db.prepare(
  "SELECT * FROM bookmarks WHERE user_id = ? ORDER BY id ASC",
);

const getBookmarkStatement = db.prepare(
  "SELECT * FROM bookmarks WHERE id = ? AND user_id = ?",
);

const createBookmark = db.prepare(`
  INSERT INTO bookmarks (user_id, url, title, description, folder_id, created_at, updated_at)
  VALUES (@user_id, @url, @title, @description, @folder_id, @created_at, @updated_at)
`);

const updateBookmark = db.prepare(`
  UPDATE bookmarks
  SET url = @url,
      title = @title,
      description = @description,
      folder_id = @folder_id,
      updated_at = @updated_at
  WHERE id = @id AND user_id = @user_id
`);

const deleteBookmark = db.prepare("DELETE FROM bookmarks WHERE id = ? AND user_id = ?");

const listFoldersStatement = db.prepare(
  "SELECT * FROM folders WHERE user_id = ? ORDER BY id ASC",
);

const getFolderStatement = db.prepare("SELECT * FROM folders WHERE id = ? AND user_id = ?");

const getFolderBookmarksStatement = db.prepare(
  "SELECT * FROM bookmarks WHERE folder_id = ? AND user_id = ? ORDER BY id ASC",
);

const createFolder = db.prepare(`
  INSERT INTO folders (user_id, name, created_at, updated_at)
  VALUES (@user_id, @name, @created_at, @updated_at)
`);

const updateFolder = db.prepare(`
  UPDATE folders
  SET name = @name,
      updated_at = @updated_at
  WHERE id = @id AND user_id = @user_id
`);

const clearFolderBookmarks = db.prepare(
  "UPDATE bookmarks SET folder_id = NULL, updated_at = @updated_at WHERE folder_id = @folder_id AND user_id = @user_id",
);

const deleteFolderStatement = db.prepare("DELETE FROM folders WHERE id = ? AND user_id = ?");

const deleteFolder = db.transaction((id: number, userId: number) => {
  clearFolderBookmarks.run({
    folder_id: id,
    user_id: userId,
    updated_at: new Date().toISOString(),
  });
  deleteFolderStatement.run(id, userId);
});

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

const isValidEmail = (value: unknown): value is string =>
  typeof value === "string" && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

const isValidPassword = (value: unknown): value is string =>
  typeof value === "string" && value.length >= 8;

const parseId = (value: string): number | null => {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const parseOptionalFolderId = (
  value: unknown,
): { ok: true; folderId: number | null | undefined } | { ok: false } => {
  if (value === undefined) {
    return { ok: true, folderId: undefined };
  }

  if (value === null) {
    return { ok: true, folderId: null };
  }

  if (typeof value === "number" && Number.isInteger(value) && value > 0) {
    return { ok: true, folderId: value };
  }

  return { ok: false };
};

const toPublicUser = (user: User): PublicUser => ({
  id: user.id,
  email: user.email,
  created_at: user.created_at,
});

const getUserByEmail = (email: string): User | undefined =>
  getUserByEmailStatement.get(email) as User | undefined;

const getUserById = (id: number): User | undefined =>
  getUserByIdStatement.get(id) as User | undefined;

const listBookmarks = (userId: number): Bookmark[] =>
  listBookmarksStatement.all(userId) as Bookmark[];

const getBookmark = (id: number, userId: number): Bookmark | undefined =>
  getBookmarkStatement.get(id, userId) as Bookmark | undefined;

const listFolders = (userId: number): Folder[] =>
  listFoldersStatement.all(userId) as Folder[];

const getFolder = (id: number, userId: number): Folder | undefined =>
  getFolderStatement.get(id, userId) as Folder | undefined;

const getFolderWithBookmarks = (
  id: number,
  userId: number,
): FolderWithBookmarks | undefined => {
  const folder = getFolder(id, userId);

  if (!folder) {
    return undefined;
  }

  return {
    ...folder,
    bookmarks: getFolderBookmarksStatement.all(id, userId) as Bookmark[],
  };
};

const folderExists = (id: number, userId: number): boolean =>
  getFolder(id, userId) !== undefined;

const authenticatedUserId = (req: express.Request): number =>
  (req as unknown as AuthenticatedRequest).user.id;

const authenticate: express.RequestHandler = (req, res, next) => {
  const authorization = req.header("Authorization");
  const [scheme, token] = authorization?.split(" ") ?? [];

  if (scheme !== "Bearer" || !token) {
    res.status(401).json({ error: "authentication required" });
    return;
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET) as JwtPayload;

    if (!Number.isInteger(payload.userId) || !getUserById(payload.userId)) {
      res.status(401).json({ error: "invalid token" });
      return;
    }

    (req as AuthenticatedRequest).user = { id: payload.userId };
    next();
  } catch {
    res.status(401).json({ error: "invalid token" });
  }
};

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/auth/register", (req, res) => {
  const { email, password } = req.body as {
    email?: unknown;
    password?: unknown;
  };

  if (!isValidEmail(email)) {
    res.status(400).json({ error: "email must be valid" });
    return;
  }

  if (!isValidPassword(password)) {
    res.status(400).json({ error: "password must be at least 8 characters" });
    return;
  }

  const normalizedEmail = email.trim().toLowerCase();

  if (getUserByEmail(normalizedEmail)) {
    res.status(409).json({ error: "email already exists" });
    return;
  }

  const result = createUserStatement.run({
    email: normalizedEmail,
    password_hash: bcrypt.hashSync(password, 10),
    created_at: new Date().toISOString(),
  });

  const user = getUserById(Number(result.lastInsertRowid));
  res.status(201).json(toPublicUser(user as User));
});

app.post("/auth/login", (req, res) => {
  const { email, password } = req.body as {
    email?: unknown;
    password?: unknown;
  };

  if (!isValidEmail(email) || typeof password !== "string") {
    res.status(400).json({ error: "email and password are required" });
    return;
  }

  const user = getUserByEmail(email.trim().toLowerCase());

  if (!user || !bcrypt.compareSync(password, user.password_hash)) {
    res.status(401).json({ error: "invalid credentials" });
    return;
  }

  const token = jwt.sign({ userId: user.id }, JWT_SECRET);
  res.status(200).json({ token });
});

app.use(["/bookmarks", "/folders"], authenticate);

app.post("/bookmarks", (req, res) => {
  const userId = authenticatedUserId(req);
  const { url, title, description, folder_id } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
    folder_id?: unknown;
  };

  if (!isNonEmptyString(url)) {
    res.status(400).json({ error: "url must be a non-empty string" });
    return;
  }

  if (!isNonEmptyString(title)) {
    res.status(400).json({ error: "title must be a non-empty string" });
    return;
  }

  const parsedFolderId = parseOptionalFolderId(folder_id);

  if (!parsedFolderId.ok) {
    res.status(400).json({ error: "folder_id must reference an existing folder" });
    return;
  }

  if (
    parsedFolderId.folderId !== undefined &&
    parsedFolderId.folderId !== null &&
    !folderExists(parsedFolderId.folderId, userId)
  ) {
    res.status(400).json({ error: "folder_id must reference an existing folder" });
    return;
  }

  const now = new Date().toISOString();
  const result = createBookmark.run({
    user_id: userId,
    url: url.trim(),
    title: title.trim(),
    description: typeof description === "string" ? description : null,
    folder_id: parsedFolderId.folderId ?? null,
    created_at: now,
    updated_at: now,
  });

  const bookmark = getBookmark(Number(result.lastInsertRowid), userId);
  res.status(201).json(bookmark);
});

app.get("/bookmarks", (req, res) => {
  const userId = authenticatedUserId(req);
  res.status(200).json(listBookmarks(userId));
});

app.get("/bookmarks/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const id = parseId(req.params.id);
  const bookmark = id === null ? undefined : getBookmark(id, userId);

  if (!bookmark) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const id = parseId(req.params.id);

  if (id === null) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  const currentBookmark = getBookmark(id, userId);

  if (!currentBookmark) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  const { url, title, description, folder_id } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
    folder_id?: unknown;
  };

  if (url !== undefined && !isNonEmptyString(url)) {
    res.status(400).json({ error: "url must be a non-empty string" });
    return;
  }

  if (title !== undefined && !isNonEmptyString(title)) {
    res.status(400).json({ error: "title must be a non-empty string" });
    return;
  }

  const parsedFolderId = parseOptionalFolderId(folder_id);

  if (!parsedFolderId.ok) {
    res.status(400).json({ error: "folder_id must reference an existing folder" });
    return;
  }

  if (
    parsedFolderId.folderId !== undefined &&
    parsedFolderId.folderId !== null &&
    !folderExists(parsedFolderId.folderId, userId)
  ) {
    res.status(400).json({ error: "folder_id must reference an existing folder" });
    return;
  }

  updateBookmark.run({
    id,
    user_id: userId,
    url: isNonEmptyString(url) ? url.trim() : currentBookmark.url,
    title: isNonEmptyString(title) ? title.trim() : currentBookmark.title,
    description:
      description === undefined
        ? currentBookmark.description
        : typeof description === "string"
          ? description
          : null,
    folder_id:
      parsedFolderId.folderId === undefined
        ? currentBookmark.folder_id
        : parsedFolderId.folderId,
    updated_at: new Date().toISOString(),
  });

  res.status(200).json(getBookmark(id, userId));
});

app.delete("/bookmarks/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const id = parseId(req.params.id);
  const result = id === null ? { changes: 0 } : deleteBookmark.run(id, userId);

  if (result.changes === 0) {
    res.status(404).json({ error: "bookmark not found" });
    return;
  }

  res.status(204).send();
});

app.post("/folders", (req, res) => {
  const userId = authenticatedUserId(req);
  const { name } = req.body as {
    name?: unknown;
  };

  if (!isNonEmptyString(name)) {
    res.status(400).json({ error: "name must be a non-empty string" });
    return;
  }

  const now = new Date().toISOString();
  const result = createFolder.run({
    user_id: userId,
    name: name.trim(),
    created_at: now,
    updated_at: now,
  });

  res.status(201).json(getFolder(Number(result.lastInsertRowid), userId));
});

app.get("/folders", (req, res) => {
  const userId = authenticatedUserId(req);
  res.status(200).json(listFolders(userId));
});

app.get("/folders/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const id = parseId(req.params.id);
  const folder = id === null ? undefined : getFolderWithBookmarks(id, userId);

  if (!folder) {
    res.status(404).json({ error: "folder not found" });
    return;
  }

  res.status(200).json(folder);
});

app.put("/folders/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const id = parseId(req.params.id);

  if (id === null || !folderExists(id, userId)) {
    res.status(404).json({ error: "folder not found" });
    return;
  }

  const { name } = req.body as {
    name?: unknown;
  };

  if (name !== undefined && !isNonEmptyString(name)) {
    res.status(400).json({ error: "name must be a non-empty string" });
    return;
  }

  const currentFolder = getFolder(id, userId) as Folder;

  updateFolder.run({
    id,
    user_id: userId,
    name: isNonEmptyString(name) ? name.trim() : currentFolder.name,
    updated_at: new Date().toISOString(),
  });

  res.status(200).json(getFolder(id, userId));
});

app.delete("/folders/:id", (req, res) => {
  const userId = authenticatedUserId(req);
  const id = parseId(req.params.id);

  if (id === null || !folderExists(id, userId)) {
    res.status(404).json({ error: "folder not found" });
    return;
  }

  deleteFolder(id, userId);

  res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;

