+};
+
+const parsePositiveIntegerQuery = (
+  value: unknown,
+  defaultValue: number,
+): number | null => {
+  if (value === undefined) {
+    return defaultValue;
+  }
+
+  if (typeof value !== "string" || !/^\d+$/.test(value)) {
+    return null;
+  }
+
+  const parsed = Number(value);
+  return Number.isSafeInteger(parsed) ? parsed : null;
+};
+
+const parsePaginationParams = (query: express.Request["query"]): PaginationParams | null => {
+  const page = parsePositiveIntegerQuery(query.page, 1);
+  const limit = parsePositiveIntegerQuery(query.limit, 20);
+
+  if (
+    page === null ||
+    limit === null ||
+    page < 1 ||
+    limit < 1 ||
+    limit > 100 ||
+    (page - 1) * limit > Number.MAX_SAFE_INTEGER
+  ) {
+    return null;
+  }
+
+  return { page, limit };
+};
+
+const parseOptionalFolderId = (
+  value: unknown,
+): { ok: true; folderId: number | null | undefined } | { ok: false } => {
+  if (value === undefined) {
+    return { ok: true, folderId: undefined };
+  }
+
+  if (value === null) {
+    return { ok: true, folderId: null };
+  }
+
+  if (typeof value === "number" && Number.isInteger(value) && value > 0) {
+    return { ok: true, folderId: value };
+  }
+
+  return { ok: false };
+};
